import React, { ReactElement, useEffect, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { useNavigate } from 'react-router';

import { ChartDate, ChartEvent } from '../../../models/Chart';
import Category from '../../../models/Category';
import HomeChart, { ChartData, DataKey } from '../../HomeChart/HomeChart';
import MediaTreemap from '../../MediaTreemap/MediaTreemap';
import InfoIcon from '../../SVGs/InfoIcon';
import LoadingPage from '../../Loading/LoadingPage';
import Presentation from '../Presentation/Presentation';
import Tooltip from '../../Tooltip/Tooltip';
import useAnchoredCategory from '../../../hooks/useAnchoredCategory';
import useOnScreen from '../../../hooks/useOnScreen';
import useWindowSize from '../../../hooks/useWindowSize';
import variables from '../../../assets/styles/variables.module.scss';
import './CategorySection.scss';

type Props = {
  category: Category;
  cta?: boolean;
  data: ChartDate[];
  events?: ChartEvent[];
  yAxis: { min: number; max: number };
}

const colorMap = {
  [Category.PUBLIC_OPINION]: variables['accent1-dark'],
  [Category.MEDIA]: variables['accent2-dark'],
  [Category.AUTHORITIES]: variables['accent3-dark'],
  [Category.COMMON]: variables.primary,
};

const showMediaTreemap = process.env.REACT_APP_ENABLE_MEDIA_TREEMAP === 'true';

const reduceData = (data: ChartData[], nextData: ChartData): ChartData[] => {
  const found = data.findIndex(({ name }) => name === nextData.name);
  const newData = [...data];
  if (found < 0) {
    newData.push(nextData);
  } else {
    newData[found] = {
      ...data[found],
      ...nextData
    };
  }
  return newData;
};

const CategorySection = ({
  category, data, events, yAxis, cta: hasCTA,
}: Props): ReactElement => {
  const { t } = useTranslation('Category');
  const className = `CategorySection section-outer ${category}`;
  const hasData = useMemo(() => data.length > 1 || (data.length === 1 && data[0].data?.length > 0), [data]);
  const useTreemap = category === Category.MEDIA && showMediaTreemap;

  const { height } = useWindowSize();
  const [ref, onScreen] = useOnScreen(`-${height/2}px`);
  const { anchoredCategory } = useAnchoredCategory();
  const navigate = useNavigate();

  // scroll to section on mount
  useEffect(() => {
    if (anchoredCategory === category) {
      (ref.current as HTMLDivElement)?.scrollTo({ behavior: 'smooth' })
    }
  }, [anchoredCategory]);

  // navigate to #category when component is on screen
  useEffect(() => {
    if (onScreen) {
      navigate(`/#${category}`, { replace: true })
    }
  }, [onScreen]);

  const dataKey = useMemo((): DataKey[] => (data.length === 1
    ? [{ key: data[0].category || Category.COMMON }]
    : data.map(({ category }) => ({ key: category || '', color: colorMap[category || Category.COMMON] }))
  ), [data]);

  const filteredData = useMemo((): ChartData[] =>
    data.map(({ category, data }: ChartDate) =>
      (data || []).map(({ date: name, y, change }) => ({
        name,
        [category as string]: y,
        [`${category as string}-change`]: change,
      }))).flat().reduce(reduceData, []).sort(({name: name1}, {name: name2}) => {
        if (name1 < name2){
          return -1;
        }
        if (name1 > name2){
          return 1;
        }
        return 0;
      }), [data]);

  return (
    <div className={className} id={category} ref={ref}>
      <div className="section-inner">
        <Presentation hasCTA={hasCTA} category={category} />
        {
          category === Category.COMMON ? (
            <span className="CategorySection-chart-tooltip-wrapper">
              {t(`${category}.about`)}
              <Tooltip content={t(`${category}.tooltip`)} className="CategorySection-chart-tooltip">
                <InfoIcon />
              </Tooltip>
            </span>
          ) : null
        }
        <div className={`CategorySection-chart-area${useTreemap ? ' has-treemap' : ''}`}>
          {useTreemap && <MediaTreemap />}
          {!useTreemap && hasData && (
            <HomeChart
              data={filteredData}
              dataKeys={dataKey}
              events={events}
              yAxis={yAxis}
            />
          )}
          {!useTreemap && !hasData && <LoadingPage />}
        </div>
      </div>
    </div>
  );
};

export default CategorySection;
