import React, { FunctionComponent, memo } from 'react';
import { DataContextConsumer } from '../../context/DataContext';
import Category from '../../models/Category';
import CategorySection from './CategorySection/CategorySection';

const Sections: FunctionComponent = () => (
    <DataContextConsumer>
      {({ categories, chartsEvents, chartsData, ...categoriesChartData }) => {
      const allDataPoints = chartsData
        ?.map(({ data }) => data ?? { y: 50 })
        .flat()
        .map(({ y }) => y);
      const yAxis = {
        min: Math.min(...allDataPoints ?? []),
        max: Math.max(...allDataPoints ?? []),
      };
      const categorySections = categories.map((category) => {
        const data = categoriesChartData?.[`chartData${category}`];
        return (
          <CategorySection
            key={`section-${category}`}
            category={category}
            data={data ? [data]: []}
            events={chartsEvents}
            yAxis={yAxis}
            cta
          />
        );
      });
      return <>
        <CategorySection
          key={`section-${Category.COMMON}`}
          category={Category.COMMON}
          data={chartsData ?? []}
          events={chartsEvents}
          yAxis={yAxis}
        />
        {categorySections}
        </>
      }}
    </DataContextConsumer>
  );

export default memo(Sections);
